        // Application State
        let map;
        let markers = {};
        let infoWindows = {};
        let focusedNode = null;
        let currentView = '2d'; // '2d' or '3d'
        let polylines = []; // Store communication lines
        let visibleMarkerTypes = {
            node: true,
            'ground-station': true,
            array: true,
            teleport: true,
            connecting: true
        }; // Track which marker types are visible

        // DOM Elements
        const totalNodesEl = document.getElementById('totalNodes');
        const activeCountEl = document.getElementById('activeCount');
        const connectingCountEl = document.getElementById('connectingCount');
        const totalCapacityEl = document.getElementById('totalCapacity');
        const nodesListEl = document.getElementById('nodesList');
        const nodeDetailsEl = document.getElementById('nodeDetails');
        const detailsPanel = document.getElementById('detailsPanel');

        // Get marker icon based on node type
        function getMarkerIcon(node) {
            const isActive = node.status.includes('Active');

            switch(node.type) {
                case 'teleport':
                    return {
                        path: google.maps.SymbolPath.CIRCLE,
                        scale: 12,
                        fillColor: '#ec4899',
                        fillOpacity: 1,
                        strokeColor: '#fbbf24',
                        strokeWeight: 3,
                    };
                case 'ground-station':
                    return {
                        path: google.maps.SymbolPath.CIRCLE,
                        scale: 10,
                        fillColor: '#f59e0b',
                        fillOpacity: 1,
                        strokeColor: '#dc2626',
                        strokeWeight: 3,
                    };
                case 'array':
                    return {
                        path: google.maps.SymbolPath.CIRCLE,
                        scale: 11,
                        fillColor: '#8b5cf6',
                        fillOpacity: 1,
                        strokeColor: '#60a5fa',
                        strokeWeight: 3,
                    };
                default: // 'node'
                    return {
                        path: google.maps.SymbolPath.CIRCLE,
                        scale: 8,
                        fillColor: isActive ? '#10b981' : '#f59e0b',
                        fillOpacity: 1,
                        strokeColor: '#ffffff',
                        strokeWeight: 2,
                    };
            }
        }

        // Initialize Google Map
        async function initMap() {
            currentView = '2d';
            updateViewButtons();
            const { Map } = await google.maps.importLibrary('maps');

            map = new Map(document.getElementById('map'), {
                zoom: 2,
                center: { lat: 20, lng: 0 },
                mapTypeId: 'satellite',
                fullscreenControl: true,
                mapTypeControl: true,
                streetViewControl: false,
            });

            // Add markers for each node
            NETWORK_NODES.forEach(node => {
                const icon = getMarkerIcon(node);

                const marker = new google.maps.Marker({
                    position: { lat: node.latitude, lng: node.longitude },
                    map: map,
                    icon: icon,
                    title: node.name,
                });

                const infoWindow = new google.maps.InfoWindow({
                    content: createInfoWindowContent(node),
                });

                marker.addListener('click', () => {
                    // Close all info windows
                    Object.values(infoWindows).forEach(iw => iw.close());

                    // Open selected info window
                    infoWindow.open(map, marker);

                    // Update focused node
                    setFocusedNode(node);
                });

                markers[node.id] = marker;
                infoWindows[node.id] = infoWindow;
            });

            updateStats();
            initializeNodesList();
            initializeMarkerToggles();
        }

        // Create info window content
        function createInfoWindowContent(node) {
            const typeLabel = node.type === 'teleport' ? '⚡ Teleport Station' :
                            node.type === 'ground-station' ? '🛰️ Ground Station' : 
                            node.type === 'array' ? '📡 Array' : 
                            '🔵 Network Node';
            const description = node.description ? '<p><span class="detail-label">Type:</span> ' + node.description + '</p>' : '';
            const link = node.url ? '<p><a href="' + node.url + '" target="_blank" style="color: #3b82f6; text-decoration: none; font-weight: 500;">🔗 Visit Website</a></p>' : '';

            return '<div class="info-window">' +
                '<h4>' + node.name + '</h4>' +
                '<p><span class="detail-label">Marker:</span> ' + typeLabel + '</p>' +
                description +
                '<p><span class="detail-label">Status:</span> ' + node.status + '</p>' +
                '<p><span class="detail-label">Region:</span> ' + node.region + '</p>' +
                '<p><span class="detail-label">Capacity:</span> ' + node.capacity + ' Q</p>' +
                '<p><span class="detail-label">Lat/Lon:</span> ' + node.latitude.toFixed(4) + ', ' + node.longitude.toFixed(4) + '</p>' +
                link +
                '</div>';
        }

        // Toggle marker visibility by type
        function toggleMarkerType(type, visible) {
            visibleMarkerTypes[type] = visible;

            // Update all markers of this type
            NETWORK_NODES.forEach(node => {
                if (node.type === type) {
                    const marker = markers[node.id];
                    if (marker) {
                        marker.setVisible(visible);
                    }
                }
            });
        }

        // Get marker type based on status (for connecting status)
        function getMarkerType(node) {
            if (node.type === 'connecting' || node.status.includes('Connecting')) {
                return 'connecting';
            }
            return node.type;
        }

        // Initialize marker toggle listeners
        function initializeMarkerToggles() {
            document.querySelectorAll('.marker-toggle').forEach(toggle => {
                toggle.addEventListener('change', (e) => {
                    const type = e.target.getAttribute('data-type');
                    const visible = e.target.checked;
                    toggleMarkerType(type, visible);
                });
            });
        }

        // Clear all communication lines
        function clearCommunicationLines() {
            polylines.forEach(polyline => polyline.setMap(null));
            polylines = [];
        }

        // Build network graph based on proximity and type priorities
        function buildNetworkGraph(maxDistanceKm = 8000) {
            const graph = {};

            // Initialize graph
            NETWORK_NODES.forEach(node => {
                graph[node.id] = [];
            });

            // Create connections based on distance and prioritization
            NETWORK_NODES.forEach(node => {
                const connections = NETWORK_NODES
                    .filter(n => n.id !== node.id)
                    .map(n => ({
                        id: n.id,
                        node: n,
                        distance: calculateDistance(
                            node.latitude, node.longitude,
                            n.latitude, n.longitude
                        ),
                        priority: n.type === 'teleport' ? 3 : 
                                 (n.type === 'ground-station' || n.type === 'array') ? 2 : 1
                    }))
                    .filter(c => c.distance <= maxDistanceKm)
                    .sort((a, b) => {
                        if (b.priority !== a.priority) return b.priority - a.priority;
                        return a.distance - b.distance;
                    })
                    .slice(0, 8); // Each node connects to up to 8 nearest priority nodes

                connections.forEach(c => {
                    graph[node.id].push(c.id);
                });
            });

            return graph;
        }

        // BFS to find shortest path distances
        function findHopDistances(startNodeId, graph, maxHops = 3) {
            const distances = {};
            const queue = [];

            NETWORK_NODES.forEach(node => {
                distances[node.id] = Infinity;
            });

            distances[startNodeId] = 0;
            queue.push(startNodeId);

            let head = 0;
            while (head < queue.length) {
                const currentId = queue[head];
                head++;

                if (distances[currentId] >= maxHops) continue;

                graph[currentId].forEach(neighborId => {
                    if (distances[neighborId] > distances[currentId] + 1) {
                        distances[neighborId] = distances[currentId] + 1;
                        queue.push(neighborId);
                    }
                });
            }

            return distances;
        }

        // Draw communication lines with hop-distance layering
        function drawCommunicationLines(selectedNode) {
            clearCommunicationLines();

            // Build the network graph
            const graph = buildNetworkGraph();

            // Find hop distances from selected node
            const hopDistances = findHopDistances(selectedNode.id, graph);

            // Define styles for each hop
            const hopStyles = {
                1: { color: '#10b981', opacity: 1.0, weight: 2.5, dash: null, label: '1-Hop' },
                2: { color: '#f59e0b', opacity: 0.7, weight: 2, dash: [5, 5], label: '2-Hop' },
                3: { color: '#ef4444', opacity: 0.5, weight: 1.5, dash: [2, 4], label: '3-Hop' }
            };

            // Draw polylines for all reachable nodes within 3 hops
            NETWORK_NODES.forEach(targetNode => {
                if (targetNode.id === selectedNode.id) return;

                const hop = hopDistances[targetNode.id];
                if (!hop || hop === Infinity || hop > 3) return;

                const style = hopStyles[hop];

                const polyline = new google.maps.Polyline({
                    path: [
                        { lat: selectedNode.latitude, lng: selectedNode.longitude },
                        { lat: targetNode.latitude, lng: targetNode.longitude }
                    ],
                    geodesic: true,
                    strokeColor: style.color,
                    strokeOpacity: style.opacity,
                    strokeWeight: style.weight,
                    strokeDasharray: style.dash,
                    map: map,
                    title: hop + '-hop to ' + targetNode.name
                });

                polylines.push(polyline);
            });

            // Update sidebar with hop statistics
            updateHopStatistics(selectedNode, hopDistances);
        }

        // Update statistics showing reachability
        function updateHopStatistics(selectedNode, hopDistances) {
            const hop1 = Object.values(hopDistances).filter(d => d === 1).length;
            const hop2 = Object.values(hopDistances).filter(d => d === 2).length;
            const hop3 = Object.values(hopDistances).filter(d => d === 3).length;
            const unreachable = Object.values(hopDistances).filter(d => d === Infinity).length;

            const stats = document.createElement('div');
            stats.style.cssText = 'font-size: 11px; margin-top: 12px; padding-top: 12px; border-top: 1px solid #334155;';
            stats.innerHTML = '<div style="margin-bottom: 8px;"><strong>Network Reach:</strong></div>' +
                '<div style="display: flex; align-items: center; gap: 6px; margin-bottom: 4px;">' +
                '<div style="width: 12px; height: 12px; background-color: #10b981; border-radius: 2px;"></div>' +
                '<span>1-Hop: <strong>' + hop1 + '</strong></span></div>' +
                '<div style="display: flex; align-items: center; gap: 6px; margin-bottom: 4px;">' +
                '<div style="width: 12px; height: 12px; background-color: #f59e0b; border-radius: 2px; opacity: 0.7;"></div>' +
                '<span>2-Hop: <strong>' + hop2 + '</strong></span></div>' +
                '<div style="display: flex; align-items: center; gap: 6px;">' +
                '<div style="width: 12px; height: 12px; background-color: #ef4444; border-radius: 2px; opacity: 0.5;"></div>' +
                '<span>3-Hop: <strong>' + hop3 + '</strong></span></div>';

            // Add to details panel if it exists
            const detailsContent = document.querySelector('.node-details');
            const existingStats = detailsContent?.querySelector('[style*="Network Reach"]')?.parentElement;
            if (existingStats) {
                existingStats.remove();
            }
            if (detailsContent) {
                detailsContent.appendChild(stats);
            }
        }

        // Calculate distance between two coordinates using Haversine formula
        function calculateDistance(lat1, lon1, lat2, lon2) {
            const R = 6371; // Earth's radius in km
            const dLat = (lat2 - lat1) * Math.PI / 180;
            const dLon = (lon2 - lon1) * Math.PI / 180;
            const a = Math.sin(dLat / 2) * Math.sin(dLat / 2) +
                Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
                Math.sin(dLon / 2) * Math.sin(dLon / 2);
            const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
            return R * c;
        }

        // Draw communication lines with hop-distance layering
        function drawCommunicationLinesLegacy(selectedNode) {
            clearCommunicationLines();

            // Find the 5 nearest nodes, prioritizing teleport stations and ground stations
            const distances = NETWORK_NODES
                .filter(n => n.id !== selectedNode.id)
                .map(node => ({
                    node: node,
                    distance: calculateDistance(
                        selectedNode.latitude, selectedNode.longitude,
                        node.latitude, node.longitude
                    ),
                    // Priority score: teleport=3, ground-station=2, array=2, node=1
                    priority: node.type === 'teleport' ? 3 : 
                             (node.type === 'ground-station' || node.type === 'array') ? 2 : 1
                }))
                .sort((a, b) => {
                    // Sort by priority first (descending), then by distance (ascending)
                    if (b.priority !== a.priority) return b.priority - a.priority;
                    return a.distance - b.distance;
                })
                .slice(0, 5);

            // Draw polylines to the nearest/prioritized nodes
            distances.forEach(item => {
                const polyline = new google.maps.Polyline({
                    path: [
                        { lat: selectedNode.latitude, lng: selectedNode.longitude },
                        { lat: item.node.latitude, lng: item.node.longitude }
                    ],
                    geodesic: true,
                    strokeColor: item.node.type === 'teleport' ? '#ec4899' : 
                                item.node.type === 'ground-station' ? '#f59e0b' :
                                item.node.type === 'array' ? '#8b5cf6' : '#10b981',
                    strokeOpacity: 0.7,
                    strokeWeight: 2,
                    map: map
                });
                polylines.push(polyline);
            });
        }

        // Set focused node
        function setFocusedNode(node) {
            focusedNode = node;
            if (map) {
