                    setFocusedNode(node);

                    // Pan to node
                    map.panTo({ lat: node.latitude, lng: node.longitude });
                    map.setZoom(4);

                    // Open info window
                    Object.values(infoWindows).forEach(iw => iw.close());
                    infoWindows[node.id].open(map, markers[node.id]);
                });
            });
        }

        // Update UI
        function updateUI() {
            initializeNodesList();
            updateStats();
            updateNodeDetails();
        }

        // Update statistics
        function updateStats() {
            totalNodesEl.textContent = NETWORK_NODES.length;
            activeCountEl.textContent = NETWORK_NODES.filter(n => n.status.includes('Active')).length;
            connectingCountEl.textContent = NETWORK_NODES.filter(n => n.status.includes('Connecting')).length;
            totalCapacityEl.textContent = NETWORK_NODES.reduce((sum, n) => sum + n.capacity, 0) + ' Q';
        }

        // Update node details
        function updateNodeDetails() {
            if (focusedNode) {
                const typeLabel = focusedNode.type === 'teleport' ? '⚡ Teleport Station' :
                                focusedNode.type === 'ground-station' ? '🛰️ Ground Station' : 
                                focusedNode.type === 'array' ? '📡 Array' : 
                                '🔵 Network Node';
                const description = focusedNode.description ? '<div class="detail-item"><span class="detail-label">Type:</span> ' + focusedNode.description + '</div>' : '';

                detailsPanel.style.display = 'block';
                nodeDetailsEl.innerHTML = '<div class="node-details">' +
                    '<div class="detail-item"><span class="detail-label">Name:</span> ' + focusedNode.name + '</div>' +
                    '<div class="detail-item"><span class="detail-label">Marker:</span> ' + typeLabel + '</div>' +
                    description +
                    '<div class="detail-item"><span class="detail-label">Status:</span> ' + focusedNode.status + '</div>' +
                    '<div class="detail-item"><span class="detail-label">Region:</span> ' + focusedNode.region + '</div>' +
                    '<div class="detail-item"><span class="detail-label">Capacity:</span> ' + focusedNode.capacity + ' Q</div>' +
                    '<div class="detail-item"><span class="detail-label">Lat/Lon:</span> ' + focusedNode.latitude.toFixed(4) + ', ' + focusedNode.longitude.toFixed(4) + '</div>' +
                    '</div>';
            } else {
                detailsPanel.style.display = 'none';
                nodeDetailsEl.innerHTML = '';
            }
        }

        // Switch to 2D map view
        function switchTo2DMap() {
            if (currentView === '2d') return;
            currentView = '2d';
            updateViewButtons();

            // Reset map tilt and heading to 0 for flat 2D view
            map.setTilt(0);
            if (map.getHeading) map.setHeading(0);

            // Change to a standard map type
            map.setMapTypeId('satellite');
        }

        // Switch to 3D globe view
        function switchTo3DGlobe() {
            if (currentView === '3d') return;
            currentView = '3d';
            updateViewButtons();

            // Enable 3D globe view with tilt and heading
            map.setMapTypeId('satellite');
            map.setTilt(45);
            if (map.setHeading) map.setHeading(45);
        }

        // Update button styles based on current view
        function updateViewButtons() {
            const btn2d = document.getElementById('view2dBtn');
            const btn3d = document.getElementById('view3dBtn');

            if (currentView === '2d') {
                btn2d.style.backgroundColor = '#2563eb';
                btn3d.style.backgroundColor = '#64748b';
            } else {
                btn2d.style.backgroundColor = '#64748b';
                btn3d.style.backgroundColor = '#2563eb';
            }
        }

        // Initialize map when page loads
        window.addEventListener('load', initMap);

