        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }
        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
            background-color: #0f172a;
            color: #e2e8f0;
            padding: 20px;
        }
        .container {
            width: 100%;
            max-width: 1400px;
            margin: 0 auto;
            padding: 24px;
            background-color: #0f172a;
            border-radius: 8px;
        }
        .header {
            margin-bottom: 24px;
        }
        .header h1 {
            font-size: 32px;
            font-weight: 700;
            color: #ffffff;
            margin-bottom: 8px;
        }
        .header p {
            color: #9ca3af;
        }
        .content-wrapper {
            display: grid;
            grid-template-columns: 1fr 320px;
            gap: 24px;
        }
        #map {
            width: 100%;
            height: 600px;
            border-radius: 8px;
            border: 1px solid #334155;
        }
        .sidebar {
            display: flex;
            flex-direction: column;
            gap: 24px;
            max-height: 600px;
            overflow-y: auto;
        }
        .panel {
            background-color: #1e293b;
            border-radius: 8px;
            padding: 16px;
            border: 1px solid #334155;
        }
        .panel h3 {
            font-size: 16px;
            font-weight: 700;
            color: #ffffff;
            margin-bottom: 12px;
        }
        .stat-item {
            margin-bottom: 12px;
        }
        .stat-label {
            color: #9ca3af;
            font-size: 12px;
        }
        .stat-value {
            font-size: 24px;
            font-weight: 700;
            margin-top: 4px;
        }
        .stat-value.green {
            color: #4ade80;
        }
        .stat-value.yellow {
            color: #facc15;
        }
        .stat-value.blue {
            color: #60a5fa;
        }

        .node-list {
            max-height: 280px;
            overflow-y: auto;
        }
        .node-item {
            width: 100%;
            text-align: left;
            padding: 8px;
            border-radius: 4px;
            border: none;
            background-color: #0f172a;
